// DJ OPUS - MEGA MIX v2
// Robert Miles - Children vibes. Clean. Dreamy. Space.
// All transitions via sliders. No hard cuts.
setcps(138/60/4)

// === YOUR DECK ===
let kickVol = slider(0.8, 0, 1.1, 0.01, "KICK")
let bassVol = slider(0.4, 0, 0.7, 0.01, "BASS")
let hatVol = slider(0.3, 0, 0.5, 0.01, "HATS")
let pianoVol = slider(0.4, 0, 0.6, 0.01, "PIANO Lead")
let padVol = slider(0.3, 0, 0.5, 0.01, "PAD Depth")
let sweepFilter = slider(2000, 200, 10000, 10, "FILTER SWEEP")
let acidVol = slider(0, 0, 0.6, 0.01, "ACID 303")
let delayMix = slider(0.3, 0, 0.7, 0.01, "DELAY Wash")

// KICK - clean four on the floor
let kick = s("bd").bank("RolandTR909")
  .gain(kickVol)
  .struct("x x x x")

// CLAP - subtle
let clap = s("cp").bank("RolandTR909")
  .gain(0.5)
  .struct("~ x ~ x")
  .room(0.2)

// HATS - gentle offbeat
let hats = s("hh").bank("RolandTR909")
  .gain(hatVol)
  .struct("~ x ~ x ~ x ~ x")

// BASS - simple, deep, rolling
let bass = note("<a1 a1 e1 e1 f1 f1 d1 d1>".slow(2))
  .s("sawtooth")
  .cutoff(perlin.range(200, 1200).slow(8))
  .resonance(10)
  .decay(0.3)
  .sustain(0.1)
  .gain(bassVol)

// PIANO LEAD - the Robert Miles moment
// Dreamy melody with delay, lots of space
let piano = note("a4 ~ e5 c5 ~ ~ a4 ~ ~ e4 a4 c5 ~ e5 ~ ~".slow(2))
  .s("triangle")
  .cutoff(sweepFilter)
  .resonance(2)
  .attack(0.01)
  .decay(0.6)
  .sustain(0.1)
  .gain(pianoVol)
  .delay(delayMix)
  .delaytime(3/8)
  .delayfeedback(0.45)
  .room(0.6)

// PAD - warm sawtooth bed, simple
let pad = note("<[a2,e3] [e2,b2] [f2,c3] [d2,a2]>".slow(4))
  .s("sawtooth")
  .cutoff(perlin.range(300, 2000).slow(16))
  .resonance(5)
  .attack(1.5)
  .decay(2)
  .sustain(0.5)
  .release(2)
  .gain(padVol)
  .room(0.85)
  .size(0.9)

// ACID - bring in when you want edge
let acid = note("<a2 a2 c3 a2 e2 e2 g2 e2>")
  .s("sawtooth")
  .cutoff(sine.range(300, 2500).fast(2))
  .resonance(18)
  .decay(0.15)
  .sustain(0)
  .gain(acidVol)
  .struct("x x [x x] x x [~ x] x x")

stack(kick, clap, hats, bass, piano, pad, acid)
